#!/usr/bin/env python3
"""Word Frequency CLI - Count word frequencies in text files."""

import argparse
import sys
from collections import Counter
from pathlib import Path

# Common stop words to ignore
STOP_WORDS = {
    'the', 'a', 'an', 'is', 'are', 'was', 'were', 'in', 'on', 'at', 'to', 'for',
    'of', 'and', 'or', 'but', 'not'
}


def read_file(file_path: str) -> str:
    """Read and return contents of a file."""
    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            return f.read()
    except FileNotFoundError:
        print(f"Error: File '{file_path}' not found.", file=sys.stderr)
        sys.exit(1)
    except PermissionError:
        print(f"Error: Permission denied for '{file_path}'.", file=sys.stderr)
        sys.exit(1)
    except Exception as e:
        print(f"Error reading '{file_path}': {e}", file=sys.stderr)
        sys.exit(1)


def extract_words(text: str) -> list[str]:
    """Extract words from text, converting to lowercase."""
    # Split on whitespace and punctuation, keep only alphabetic words
    words = []
    for word in text.split():
        # Strip punctuation and keep only alphabetic characters
        cleaned = ''.join(c for c in word if c.isalpha())
        if cleaned:
            words.append(cleaned.lower())
    return words


def count_words(text: str) -> Counter:
    """Count word frequencies, filtering out stop words."""
    words = extract_words(text)
    # Filter out stop words
    filtered_words = [w for w in words if w not in STOP_WORDS]
    return Counter(filtered_words)


def merge_counters(counters: list[Counter]) -> Counter:
    """Merge multiple Counters into one."""
    result = Counter()
    for c in counters:
        result.update(c)
    return result


def format_output(word_counts: Counter, limit: int, sort_by: str) -> str:
    """Format word counts for output."""
    if sort_by == 'alpha':
        sorted_items = sorted(word_counts.items(), key=lambda x: (x[0], -x[1]))
    else:  # sort by freq (default)
        sorted_items = word_counts.most_common(limit)
        if sort_by == 'alpha':
            sorted_items = sorted(sorted_items, key=lambda x: x[0])

    if sort_by != 'freq' or sort_by == 'alpha':
        # For alpha sort, we need to sort first then limit
        sorted_items = sorted(word_counts.items(), key=lambda x: x[0])
        sorted_items = sorted_items[:limit]

    lines = []
    for word, count in sorted_items:
        lines.append(f"{word}: {count}")
    return '\n'.join(lines)


def main():
    parser = argparse.ArgumentParser(
        description='Count word frequencies in text files.'
    )
    parser.add_argument(
        'files',
        nargs='+',
        help='One or more text files to analyze'
    )
    parser.add_argument(
        '--limit', '-n',
        type=int,
        default=10,
        help='Number of results to show (default: 10)'
    )
    parser.add_argument(
        '--sort',
        choices=['freq', 'alpha'],
        default='freq',
        help='Sort order: freq (by frequency) or alpha (alphabetical) (default: freq)'
    )

    args = parser.parse_args()

    # Read and process all files
    counters = []
    for file_path in args.files:
        content = read_file(file_path)
        if not content.strip():
            print(f"Warning: File '{file_path}' is empty.", file=sys.stderr)
            continue
        counter = count_words(content)
        counters.append(counter)

    if not counters:
        print("Error: No valid content found in any file.", file=sys.stderr)
        sys.exit(1)

    # Merge all counters
    total_counts = merge_counters(counters)

    if not total_counts:
        print("Error: No words found after filtering.", file=sys.stderr)
        sys.exit(1)

    # Get results based on sort order
    if args.sort == 'alpha':
        sorted_items = sorted(total_counts.items(), key=lambda x: x[0])
        sorted_items = sorted_items[:args.limit]
    else:
        sorted_items = total_counts.most_common(args.limit)

    # Output results
    for word, count in sorted_items:
        print(f"{word}: {count}")


if __name__ == '__main__':
    main()
